    #[test]
    fn cursor_left_multibyte_german_umlaut() {
        // ö = U+00F6, UTF-8: 0xC3 0xB6 (2 bytes)
        let input = "ö";
        assert_eq!(cursor_left(input, 2), 0); // left from end → start
        assert_eq!(cursor_left(input, 0), 0); // left at start → no-op
        assert_eq!(cursor_left(input, 1), 0); // left from mid-char → start (char boundary)
    }

    #[test]
    fn cursor_right_multibyte_german_umlaut() {
        let input = "ö";
        assert_eq!(cursor_right(input, 0), 2); // right from start → end (skips full char)
        assert_eq!(cursor_right(input, 2), 2); // right at end → no-op
    }

    #[test]
    fn cursor_left_right_multibye_mixed() {
        // "höl" = h(1) + ö(2) + l(1) = 4 bytes
        let input = "höl";
        assert_eq!(cursor_right(input, 0), 1); // h → ö
        assert_eq!(cursor_right(input, 1), 3); // ö → l
        assert_eq!(cursor_right(input, 3), 4); // l → end
        assert_eq!(cursor_left(input, 4), 3); // end → l
        assert_eq!(cursor_left(input, 3), 1); // l → ö
        assert_eq!(cursor_left(input, 1), 0); // ö → h
    }

    #[test]
    fn cursor_backspace_multibyte() {
        // "hölle" = h(1) ö(2) l(1) l(1) e(1) = 6 bytes
        // pos = 6 means cursor PAST end (after 'e')
        let mut input = String::from("hölle");
        let mut pos = 6;
        cursor_backspace(&mut input, &mut pos);
        assert_eq!(input, "höll"); // 'e' removed
        assert_eq!(pos, 5);

        // Backspace through 'ö' (2-byte char)
        // "hö" = h(1) ö(2) = 3 bytes, pos = 3 means cursor PAST end
        let mut input = String::from("hö");
        let mut pos = 3;
        cursor_backspace(&mut input, &mut pos);
        assert_eq!(input, "h"); // 'ö' removed
        assert_eq!(pos, 1);
    }

    #[test]
    fn cursor_delete_multibyte() {
        let mut input = String::from("öh");
        let mut pos = 0;
        cursor_delete(&mut input, &mut pos);
        assert_eq!(input, "h");
        assert_eq!(pos, 0);
    }

    #[test]
    fn cursor_line_col_multibyte() {
        let input = "öäü"; // 6 bytes: ö(2) ä(2) ü(2)
        assert_eq!(cursor_line_col(input, 0), (0, 0));
        assert_eq!(cursor_line_col(input, 2), (0, 2)); // after ö
        assert_eq!(cursor_line_col(input, 4), (0, 4)); // after ä
        assert_eq!(cursor_line_col(input, 6), (0, 6)); // end
    }

    #[test]
    fn cursor_left_multibyte_newline() {
        // "a\nö" = a(1) \n(1) ö(2) = 4 bytes
        let input = "a\nö";
        // pos=3 is start of 'ö' on line 1
        // prev char is '\n', so cursor_left lands on '\n' (pos=1)
        assert_eq!(cursor_left(input, 3), 1);
        // pos=1 is '\n' on line 0, col=1
        // prev char is 'a', so cursor_left → pos=0
        assert_eq!(cursor_left(input, 1), 0);
    }

    #[test]
    fn cursor_up_down_multibyte() {
        // "ö\nä" = ö(2) \n(1) ä(2) = 5 bytes
        let input = "ö\nä";
        // pos=3 is 'ä' (line 1, col 0)
        assert_eq!(cursor_up(input, 3), 0); // → 'ö' (line 0, col 0)
        assert_eq!(cursor_down(input, 0), 3); // → 'ä' (line 1, col 0)
    }

