    #[test]
    fn cursor_multibyte_emoji() {
        // 😀 = U+1F600, UTF-8: 4 bytes (F0 9F 98 80)
        let input = "😀a";
        assert_eq!(cursor_right(input, 0), 4); // skip full emoji
        assert_eq!(cursor_left(input, 5), 4); // back to emoji
        assert_eq!(cursor_left(input, 4), 0); // back to start

        let mut input = String::from("a😀");
        let mut pos = 5;
        cursor_backspace(&mut input, &mut pos);
        assert_eq!(input, "a");
        assert_eq!(pos, 1);

        let mut input = String::from("😀");
        let mut pos = 0;
        cursor_delete(&mut input, &mut pos);
        assert_eq!(input, "");
        assert_eq!(pos, 0);
    }

    // ---------------------------------------------------------------------------
    // Regression: cursor_up/down must not land inside multi-byte characters
    // ---------------------------------------------------------------------------

    #[test]
    fn cursor_down_ascii_to_multibyte_rounds_down() {
        // "abcde\na─" — line 0 is 5 bytes (ASCII), line 1 is 4 bytes (a(1) + ─(3))
        // Cursor at byte 3 in line 0 ('d'). Down should NOT land at byte 3 in line 1
        // (which is inside ─ at bytes 1..4). Should round down to byte 1 (after 'a').
        let input = "abcde\na─";
        let result = cursor_down(input, 3);
        // Byte 3 in line 1 is inside '─'. Rounds down to 1.
        // offset to line 1 = 5 + 1 = 6. Final = 6 + 1 = 7.
        assert_eq!(result, 7);
        // Verify result is a valid char boundary by slicing
        let _ = &input[..result];
    }

    #[test]
    fn cursor_up_multibyte_to_ascii_rounds_down() {
        // "a─\nabcde" — line 0 is 4 bytes (a(1) + ─(3)), line 1 is 5 bytes
        // Cursor at byte 8 in line 1 ('d', col=2). Up should land at byte 2 in line 0,
        // which is inside ─ (bytes 1..4). Should round down to byte 1 (after 'a').
        let input = "a─\nabcde";
        let result = cursor_up(input, 8); // pos 8 = line 1, col 2
        // Byte 2 in line 0 is inside '─'. Should round down to 1 (after 'a').
        assert_eq!(result, 1);
        let _ = &input[..result];
    }

    #[test]
    fn cursor_down_multibyte_to_wider_multibyte() {
        // "öäü\n😀" — line 0 = 6 bytes (ö(2) + ä(2) + ü(2)), line 1 = 4 bytes (😀)
        // Cursor at byte 5 in line 0 (inside ü, bytes 4..6). Down to line 1.
        // col=5.min(4)=4, rounds to 4 (end of line 1).
        let input = "öäü\n😀";
        let result = cursor_down(input, 5);
        // offset to line 1 = 6 + 1 = 7. Final = 7 + 4 = 11.
        assert_eq!(result, 11);
        let _ = &input[..result];
    }

    #[test]
    fn cursor_up_multibyte_to_wider_multibyte() {
        // "😀\nöäü" — line 0 = 4 bytes (😀), line 1 = 6 bytes
        // Cursor at byte 12 (past end, clamped to 11 = end of line 1, col=6).
        // Up to line 0: col=6.min(4)=4, rounds to 4 (end of line 0).
        let input = "😀\nöäü";
        let result = cursor_up(input, 12);
        assert_eq!(result, 4);
        let _ = &input[..result];
    }

    #[test]
    fn cursor_down_into_box_drawing_chars() {
        // Reproduce the exact panic scenario: pasting box-drawing characters
        // "hello\n┌────┐" — line 0 = 5 bytes, line 1 = 18 bytes (┌(3) + ─(3)*4 + ┐(3))
        // Cursor at byte 1 in line 0 ('e'). Down lands at byte 1 in line 1,
        // which is inside ┌ (bytes 0..3). Should round down to 0.
        let input = "hello\n┌────┐";
        let result = cursor_down(input, 1);
        // offset to line 1 = 5 + 1 = 6. Byte 1 rounds down to 0.
        assert_eq!(result, 6);
        let _ = &input[..result];
    }

    #[test]
    fn cursor_up_from_ascii_into_box_drawing() {
        // "┌────┐\nhello" — line 0 has box chars, line 1 is ASCII
        // Cursor at byte 22 in line 1 ('l', col=3). Up lands at byte 3 in line 0.
        // Byte 3 is the start of the first '─' (┌=0..3, ─=3..6). This IS a boundary.
        let input = "┌────┐\nhello";
        let result = cursor_up(input, 22);
        assert_eq!(result, 3);
        let _ = &input[..result];
    }

    #[test]
    fn cursor_up_from_ascii_into_box_drawing_mid_char() {
        // Same layout but cursor at byte 21 in line 1 ('e', col=1).
        // Up lands at byte 1 in line 0, which IS inside ┌ (bytes 0..3). Rounds down to 0.
        let input = "┌────┐\nhello";
        let result = cursor_up(input, 21);
        assert_eq!(result, 0);
        let _ = &input[..result];
    }

