    #[test]
    fn cursor_up_visual_single_line_noop() {
        // "hello" with wrap_width 20 → 1 visual line. Up is no-op, returns unchanged.
        let input = "hello";
        assert_eq!(cursor_up_visual(input, 0, 20), 0);
        assert_eq!(cursor_up_visual(input, 3, 20), 3);
        assert_eq!(cursor_up_visual(input, 5, 20), 5);
    }

    #[test]
    fn cursor_down_visual_single_line_noop() {
        // "hello" with wrap_width 20 → 1 visual line. Down is no-op, returns unchanged.
        let input = "hello";
        assert_eq!(cursor_down_visual(input, 0, 20), 0);
        assert_eq!(cursor_down_visual(input, 3, 20), 3);
        assert_eq!(cursor_down_visual(input, 5, 20), 5);
    }

    #[test]
    fn cursor_up_visual_wrapped_line() {
        // "hello world" wrapped at 5 → 3 visual lines
        // Vis 0: "hello" (0-5), Vis 1: " worl" (5-10), Vis 2: "d" (10-11)
        // Cursor at byte 7 ('o' in "worl") → vis line 1. Up → vis line 0, col 2.
        let input = "hello world";
        let result = cursor_up_visual(input, 7, 5);
        // vis line 0, col 2 → byte 2
        assert_eq!(result, 2);
    }

    #[test]
    fn cursor_down_visual_wrapped_line() {
        // "hello world" wrapped at 5 → 3 visual lines
        // Cursor at byte 2 ('l' in "hello") → vis line 0, col 2.
        // Down → vis line 1 (" worl"), col 2 → byte 7
        let input = "hello world";
        let result = cursor_down_visual(input, 2, 5);
        assert_eq!(result, 7);
    }

    #[test]
    fn cursor_up_visual_multiline() {
        let input = "abc\nhello world";
        // Line 0: "abc" → 1 visual line
        // Line 1: "hello world" → 3 visual lines at width 5
        // Cursor at byte 8 ('l' in "hello") → vis line 1. Up → vis line 0 ("abc"), col clamped to 3.
        let result = cursor_up_visual(input, 8, 5);
        assert_eq!(result, 3);
    }

    #[test]
    fn cursor_down_visual_multiline() {
        let input = "hello world\nabc";
        // Line 0: "hello world" → 3 visual lines at width 5
        // Line 1: "abc" → 1 visual line
        // Cursor at byte 7 ('o' in "worl") → vis line 1, col 3.
        // Down → vis line 2 ("d"), col clamped to 1 → byte 11
        let result = cursor_down_visual(input, 7, 5);
        assert_eq!(result, 11);
    }

    #[test]
    fn cursor_up_visual_at_top_returns_unchanged() {
        let input = "hello world";
        // Cursor at byte 0 → vis line 0. Up returns unchanged.
        assert_eq!(cursor_up_visual(input, 0, 5), 0);
        // Cursor at byte 3 → vis line 0. Up returns unchanged.
        assert_eq!(cursor_up_visual(input, 3, 5), 3);
    }

    #[test]
    fn cursor_down_visual_at_bottom_returns_unchanged() {
        let input = "hello world";
        // Cursor at byte 11 (past end, clamped) → vis line 2 (last). Down returns unchanged.
        assert_eq!(cursor_down_visual(input, 11, 5), 11);
        // Cursor at byte 10 ('d') → vis line 1 (because byte 10 falls in seg (5,10)). Not at bottom.
        // Down → vis line 2 ("d"), col clamped to 1 → byte 11
        assert_eq!(cursor_down_visual(input, 10, 5), 11);
    }

