    fn cursor_down_visual_multibyte_wrapped() {
        // "öäüöäü" = 12 bytes, 6 display cols. Width 2 → 3 visual lines.
        // Cursor at byte 2 ('ä' in Vis 0) → vis line 0, col 1.
        // Down → vis line 1 ("üö"), col 1 → byte 6
        let input = "öäüöäü";
        let result = cursor_down_visual(input, 2, 2);
        assert_eq!(result, 6);
    }

    #[test]
    fn cursor_up_visual_wide_to_narrow_segment() {
        // "😀😀\nab" — line 0 has 2 emoji (4 display cols), line 1 has 2 ASCII chars
        // Width 3: line 0 → 2 visual lines (😀, 😀), line 1 → 1 visual line (ab)
        // Cursor at byte 4 (second 😀) → vis line 1, col 2 (emoji width 2).
        // Up → vis line 0 (first 😀), col clamped to 2 → byte 4 (end of first 😀)
        let input = "😀😀\nab";
        let result = cursor_up_visual(input, 4, 3);
        assert_eq!(result, 4);
    }

    #[test]
    fn cursor_down_visual_crosses_logical_line() {
        // "ab\nhello world" — line 0: "ab", line 1: "hello world"
        // Width 5: line 0 → 1 vis line, line 1 → 3 vis lines
        // Cursor at byte 2 (end of "ab") → vis line 0, col 2.
        // Down → vis line 1 ("hello"), col 2 → byte 5
        let input = "ab\nhello world";
        let result = cursor_down_visual(input, 2, 5);
        assert_eq!(result, 5);
    }
